  ('locality-6f0ba476-moex-00426', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '某甲於今年8月份逝世，死亡時其名下有銀行存款1,500萬元，一棟土地公告現值與房屋評定價 格共1,000萬元房子（市價為1,600萬元），A上市公司股票10,000股，死亡日的收盤價為每股80 元，遺產稅申報日的收盤價為60元，此外並無其他日常生活器具或職業上的工具可減除。假設其 死亡時留有配偶及一名剛滿 18 歲的女兒。假設其配偶並未主張配偶剩餘財產差額分配請求權， 試問某甲應納的遺產稅額為多少？', '["481,000元", "604,000元", "614,000元", "737,000元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "72f99d566af6", "answer_pdf_sha1": "983a0c0f2b43", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1413", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00427', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '某乙於民國111年2月贈與其妻500萬元，5月於女兒結婚時贈與嫁妝300萬元，並於8月贈與 兒子現金200萬元。試問當年度某乙應納的贈與稅額為多少？', '["0元", "15.6萬元", "18萬元", "65.6萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "72f99d566af6", "answer_pdf_sha1": "983a0c0f2b43", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1413", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00428', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '丁先生取得會計師執照後欲在家開設會計師事務所，其目前住家實際共有 30 坪，目前規劃其中 一間房間（實際為3坪）做為開業場所。試問丁先生開業後其住家會有多少比例由原本的住家用 稅率改為課徵非住家用房屋稅率？', '["全數仍課徵住家用稅率", "十分之一變更為非住家用稅率", "六分之一變更為非住家用稅率", "全數課徵非住家用稅率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "72f99d566af6", "answer_pdf_sha1": "983a0c0f2b43", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1413", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00429', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '土地以下列土地所有權人之那一身分設籍，不符合土地稅法自用住宅用地之條件？', '["祖父母", "配偶", "未成年子女", "兄弟姐妹"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "72f99d566af6", "answer_pdf_sha1": "983a0c0f2b43", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1413", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00430', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '某甲去電影院買票看電影，試問此電影票所含的娛樂稅，納稅義務人為下列何者？', '["電影院場所之不動產所有人", "電影院", "該部電影的代理商或製片商", "某甲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "72f99d566af6", "answer_pdf_sha1": "983a0c0f2b43", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1413", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
